select * from customer_data limit 20

-- Q.1 What is the total revenue generated by male vs female customers?
select gender,SUM(purchase_amount) as revenue
from customer_data
group by gender;

-- Q.2 Which customers used a discount but still spent more than the average purchase amount?
select customer_id,purchase_amount
from customer_data
where discount_applied = 'Yes' and purchase_amount >= (select AVG(purchase_amount) from customer_data)

-- Q.3 Which are the top 5 products with the highest average review rating?
select item_purchased,ROUND(AVG(review_rating::numeric),2) as "Average Product Rating"
from customer_data
group by item_purchased
order by avg(review_rating) desc
limit 5;

-- Q.4 Compare the average Purchase Amounts between Standards and Express Shipping.
select shipping_type,
ROUND(AVG(purchase_amount),2)
from customer_data
where shipping_type in ('Standard','Express')
group by shipping_type

-- Q.5 Do subscribed cutomers spend more? Comapre average spend and total revenue between subscribers and non subscribers.
select subscription_status,
COUNT(customer_id) as total_customers,
ROUND(AVG(purchase_amount),2) as avg_spend,
ROUND(SUM(purchase_amount),2) as total_revenue
from customer_data
group by subscription_status
order by total_revenue,avg_spend desc;

-- Q.6 Which 5 products have the highest percentage of purchases with discount applied?
select item_purchased,
ROUND(100*SUM(CASE WHEN discount_applied = 'Yes' THEN 1 ELSE 0 END)/COUNT(*),2) as discount_rate
from customer_data
group by item_purchased
order by discount_rate desc
limit 5;

-- Q.7 Segment customers into New,Returning,and loyal based on their number of previous purchases,and show the count of each segment.
with customer_type as (
select customer_id,previous_purchases,
CASE 
   WHEN previous_purchases = 1 THEN 'New'
   WHEN previous_purchases BETWEEN 2 and 10 THEN 'Returning'
   ELSE 'Loyal Customer'
   END AS customer_segment
   from customer_data
)
select customer_segment,count(*) as "Number Of Customers"
from customer_type
group by customer_segment

-- Q.8 What are the top 3 most purchased products within each category?
with item_counts as (
select category,
item_purchased,
COUNT(customer_id) as total_orders,
ROW_NUMBER() over(partition by category order by count(customer_id)DESC) as item_rank
from customer_data
group by category,item_purchased
)
select item_rank,category,item_purchased,total_orders
from item_counts
where item_rank <= 3;

-- Q.9 Are customers who are repeat buyers (more than 5 previous purchases) also likely to subscribe?
select subscription_status,
count(customer_id) as repeat_buyers
from customer_data
where previous_purchases > 5
group by subscription_status

-- Q.10 What is the revenue contribution of each age group?
select age_group,
SUM(purchase_amount) as total_revenue
from customer_data
group by age_group
order by total_revenue desc;